using System.Drawing;
using System.Drawing.Imaging;
using System.IO;
using System.Windows;
using System.Windows.Controls;
using System.Windows.Input;
using System.Windows.Media;
using System.Windows.Media.Imaging;
using System.Windows.Shapes;
using System.Collections.Generic;
using Quicker.Public;

static Window _win;
static IDictionary<string, object> _dataContext;
static ICustomWindowContext _winContext;
static Canvas _canvas;
static System.Windows.Controls.Image _image;
static System.Windows.Shapes.Rectangle _cropBorder;
static System.Windows.Shapes.Rectangle _overlayDark;
static Button _btnOk;
static TextBlock _infoText;
static FrameworkElement _handleTL;
static FrameworkElement _handleTR;
static FrameworkElement _handleBL;
static FrameworkElement _handleBR;

static bool _isDragging;
static System.Windows.Point _startPoint;
static double _imgOffsetX;
static double _imgOffsetY;
static double _imgDisplayW;
static double _imgDisplayH;
static int _imgPixelW;
static int _imgPixelH;

static BitmapSource BitmapToBitmapSource(Bitmap bmp)
{
    using (MemoryStream ms = new MemoryStream())
    {
        bmp.Save(ms, ImageFormat.Png);
        ms.Position = 0;
        BitmapImage bi = new BitmapImage();
        bi.BeginInit();
        bi.CacheOption = BitmapCacheOption.OnLoad;
        bi.StreamSource = ms;
        bi.EndInit();
        bi.Freeze();
        return bi;
    }
}

public static void OnWindowCreated(Window win, IDictionary<string, object> dataContext, ICustomWindowContext winContext)
{
    _win = win;
    _dataContext = dataContext;
    _winContext = winContext;
}

public static void OnWindowLoaded(Window win, IDictionary<string, object> dataContext, ICustomWindowContext winContext)
{
    _canvas = win.FindName("OverlayCanvas") as Canvas;
    _image = win.FindName("SourceImage") as System.Windows.Controls.Image;
    _cropBorder = win.FindName("CropBorder") as System.Windows.Shapes.Rectangle;
    _overlayDark = win.FindName("OverlayDark") as System.Windows.Shapes.Rectangle;
    _btnOk = win.FindName("BtnOK") as Button;
    _infoText = win.FindName("InfoText") as TextBlock;
    _handleTL = win.FindName("HandleTL") as FrameworkElement;
    _handleTR = win.FindName("HandleTR") as FrameworkElement;
    _handleBL = win.FindName("HandleBL") as FrameworkElement;
    _handleBR = win.FindName("HandleBR") as FrameworkElement;

    object imgObj;
    if (dataContext.TryGetValue("img_clipboard", out imgObj) && imgObj != null)
    {
        Bitmap bmp = imgObj as Bitmap;
        if (bmp != null)
        {
            BitmapSource bs = BitmapToBitmapSource(bmp);
            _image.Source = bs;
            _imgPixelW = bmp.Width;
            _imgPixelH = bmp.Height;
        }
    }

    _canvas.PreviewMouseLeftButtonDown += OnMouseDown;
    _canvas.PreviewMouseMove += OnMouseMove;
    _canvas.PreviewMouseLeftButtonUp += OnMouseUp;
    win.SizeChanged += OnWindowSizeChanged;
    win.PreviewKeyDown += OnWindowKeyDown;

    UpdateImageMapping();
    ResetSelection();
}

static void OnWindowSizeChanged(object sender, SizeChangedEventArgs e)
{
    UpdateImageMapping();
}

static void UpdateImageMapping()
{
    if (_image == null || _image.Source == null) return;
    double containerW = _canvas.ActualWidth;
    double containerH = _canvas.ActualHeight;
    if (containerW < 1 || containerH < 1) return;
    double scaleX = containerW / _imgPixelW;
    double scaleY = containerH / _imgPixelH;
    double scale = Math.Min(scaleX, scaleY);
    _imgDisplayW = _imgPixelW * scale;
    _imgDisplayH = _imgPixelH * scale;
    _imgOffsetX = (containerW - _imgDisplayW) / 2.0;
    _imgOffsetY = (containerH - _imgDisplayH) / 2.0;
    Canvas.SetLeft(_overlayDark, 0);
    Canvas.SetTop(_overlayDark, 0);
    _overlayDark.Width = containerW;
    _overlayDark.Height = containerH;
}

static System.Windows.Point CanvasToImage(System.Windows.Point canvasPt)
{
    double imgX = (canvasPt.X - _imgOffsetX) / _imgDisplayW * _imgPixelW;
    double imgY = (canvasPt.Y - _imgOffsetY) / _imgDisplayH * _imgPixelH;
    if (imgX < 0) imgX = 0;
    if (imgY < 0) imgY = 0;
    if (imgX > _imgPixelW) imgX = _imgPixelW;
    if (imgY > _imgPixelH) imgY = _imgPixelH;
    return new System.Windows.Point(imgX, imgY);
}

static void OnMouseDown(object sender, MouseButtonEventArgs e)
{
    System.Windows.Point pos = e.GetPosition(_canvas);
    if (pos.X < _imgOffsetX || pos.X > _imgOffsetX + _imgDisplayW) return;
    if (pos.Y < _imgOffsetY || pos.Y > _imgOffsetY + _imgDisplayH) return;
    _isDragging = true;
    _startPoint = pos;
    Canvas.SetLeft(_cropBorder, pos.X);
    Canvas.SetTop(_cropBorder, pos.Y);
    _cropBorder.Width = 0;
    _cropBorder.Height = 0;
    _cropBorder.Visibility = Visibility.Visible;
    _handleTL.Visibility = Visibility.Visible;
    _handleTR.Visibility = Visibility.Visible;
    _handleBL.Visibility = Visibility.Visible;
    _handleBR.Visibility = Visibility.Visible;
    _btnOk.IsEnabled = false;
    _canvas.CaptureMouse();
}

static void OnMouseMove(object sender, MouseEventArgs e)
{
    if (!_isDragging) return;
    System.Windows.Point pos = e.GetPosition(_canvas);
    double left = Math.Min(_startPoint.X, pos.X);
    double top = Math.Min(_startPoint.Y, pos.Y);
    double right = Math.Max(_startPoint.X, pos.X);
    double bottom = Math.Max(_startPoint.Y, pos.Y);
    if (left < _imgOffsetX) left = _imgOffsetX;
    if (top < _imgOffsetY) top = _imgOffsetY;
    if (right > _imgOffsetX + _imgDisplayW) right = _imgOffsetX + _imgDisplayW;
    if (bottom > _imgOffsetY + _imgDisplayH) bottom = _imgOffsetY + _imgDisplayH;
    Canvas.SetLeft(_cropBorder, left);
    Canvas.SetTop(_cropBorder, top);
    _cropBorder.Width = right - left;
    _cropBorder.Height = bottom - top;
    System.Windows.Point imgTL = CanvasToImage(new System.Windows.Point(left, top));
    System.Windows.Point imgBR = CanvasToImage(new System.Windows.Point(right, bottom));
    int w = (int)(imgBR.X - imgTL.X);
    int h = (int)(imgBR.Y - imgTL.Y);
    _infoText.Text = string.Format("{0} x {1}", w, h);
}

static void OnMouseUp(object sender, MouseButtonEventArgs e)
{
    if (!_isDragging) return;
    _isDragging = false;
    _canvas.ReleaseMouseCapture();
    if (_cropBorder.Width < 3 || _cropBorder.Height < 3)
    {
        ResetSelection();
        return;
    }
    UpdateHandlePositions();
    _btnOk.IsEnabled = true;
}

static void UpdateHandlePositions()
{
    double cx = Canvas.GetLeft(_cropBorder);
    double cy = Canvas.GetTop(_cropBorder);
    double cw = _cropBorder.Width;
    double ch = _cropBorder.Height;
    Canvas.SetLeft(_handleTL, cx - 4);
    Canvas.SetTop(_handleTL, cy - 4);
    Canvas.SetLeft(_handleTR, cx + cw - 4);
    Canvas.SetTop(_handleTR, cy - 4);
    Canvas.SetLeft(_handleBL, cx - 4);
    Canvas.SetTop(_handleBL, cy + ch - 4);
    Canvas.SetLeft(_handleBR, cx + cw - 4);
    Canvas.SetTop(_handleBR, cy + ch - 4);
}

static void ResetSelection()
{
    _cropBorder.Width = 0;
    _cropBorder.Height = 0;
    _cropBorder.Visibility = Visibility.Collapsed;
    _handleTL.Visibility = Visibility.Collapsed;
    _handleTR.Visibility = Visibility.Collapsed;
    _handleBL.Visibility = Visibility.Collapsed;
    _handleBR.Visibility = Visibility.Collapsed;
    _btnOk.IsEnabled = false;
    _infoText.Text = "拖拽鼠标框选裁剪区域";
}

static void OnWindowKeyDown(object sender, KeyEventArgs e)
{
    if (e.Key == Key.Escape)
    {
        _win.Close();
        e.Handled = true;
    }
}

public static bool OnButtonClicked(string controlName, object controlTag, Window win, IDictionary<string, object> dataContext, ICustomWindowContext winContext)
{
    string tag = controlTag != null ? controlTag.ToString() : "";
    if (tag == "reset")
    {
        ResetSelection();
        return true;
    }
    if (tag == "cancel")
    {
        win.Close();
        return false;
    }
    if (tag == "ok")
    {
        double cx = Canvas.GetLeft(_cropBorder);
        double cy = Canvas.GetTop(_cropBorder);
        double cw = _cropBorder.Width;
        double ch = _cropBorder.Height;
        System.Windows.Point imgTL = CanvasToImage(new System.Windows.Point(cx, cy));
        System.Windows.Point imgBR = CanvasToImage(new System.Windows.Point(cx + cw, cy + ch));
        int cropX = (int)imgTL.X;
        int cropY = (int)imgTL.Y;
        int cropW = (int)(imgBR.X - imgTL.X);
        int cropH = (int)(imgBR.Y - imgTL.Y);
        if (cropX < 0) cropX = 0;
        if (cropY < 0) cropY = 0;
        if (cropX + cropW > _imgPixelW) cropW = _imgPixelW - cropX;
        if (cropY + cropH > _imgPixelH) cropH = _imgPixelH - cropY;
        dataContext["result_crop_x"] = cropX;
        dataContext["result_crop_y"] = cropY;
        dataContext["result_crop_w"] = cropW;
        dataContext["result_crop_h"] = cropH;
        win.Close();
        return false;
    }
    return true;
