using System.Drawing;
using System.Drawing.Imaging;
using System.IO;

public static void Exec(Quicker.Public.IStepContext context)
{
    object imgObj = context.GetVarValue("img_clipboard");
    Bitmap source = imgObj as Bitmap;
    if (source == null)
    {
        throw new System.Exception("无效的图片数据");
    }

    int cx = (int)context.GetVarValue("crop_x");
    int cy = (int)context.GetVarValue("crop_y");
    int cw = (int)context.GetVarValue("crop_w");
    int ch = (int)context.GetVarValue("crop_h");

    if (cx < 0) cx = 0;
    if (cy < 0) cy = 0;
    if (cx + cw > source.Width) cw = source.Width - cx;
    if (cy + ch > source.Height) ch = source.Height - cy;

    if (cw <= 0 || ch <= 0)
    {
        throw new System.Exception("裁剪区域无效");
    }

    System.Drawing.Rectangle rect = new System.Drawing.Rectangle(cx, cy, cw, ch);
    Bitmap cropped = source.Clone(rect, source.PixelFormat);

    string savePath = context.GetVarValue("save_path") as string;
    if (string.IsNullOrEmpty(savePath))
    {
        Microsoft.Win32.SaveFileDialog dlg = new Microsoft.Win32.SaveFileDialog();
        dlg.Filter = "PNG图片|*.png|JPEG图片|*.jpg|BMP图片|*.bmp|所有文件|*.*";
        dlg.DefaultExt = ".png";
        dlg.FileName = "cropped_image";
        dlg.Title = "保存裁剪后的图片";
        bool? result = dlg.ShowDialog();
        if (result != true)
        {
            throw new System.Exception("用户取消保存");
        }
        savePath = dlg.FileName;
        context.SetVarValue("save_path", savePath);
    }

    ImageFormat format = ImageFormat.Png;
    string ext = System.IO.Path.GetExtension(savePath).ToLowerInvariant();
    if (ext == ".jpg" || ext == ".jpeg")
    {
        format = ImageFormat.Jpeg;
    }
    else if (ext == ".bmp")
    {
        format = ImageFormat.Bmp;
    }

    cropped.Save(savePath, format);
    context.SetVarValue("result_img", cropped);
}"}, "reference": {"VarKey": null, "Value": ""}, "runOnUiThread": {"VarKey": null, "Value": "ui"}, "stopIfFail": {"VarKey": null, "Value": "1"}, "enableCache": {"VarKey": null, "Value": "0"}}, "OutputParams": {"isSuccess": null, "rtn": null, "errMessage": null}, "IfSteps": null, "ElseSteps": null, "Note": "裁剪并保存图片", "Disabled": false, "Collapsed": false, "DelayMs": 0, "Id": "b1a00001-0005-4000-8000-000000000005"}, {"StepRunnerKey": "sys:notify", "InputParams": {"type": {"VarKey": null, "Value": "Success"}, "msg": {"VarKey": null, "Value": "$$图片已保存到 {save_path}"}}, "OutputParams": {}, "IfSteps": null, "ElseSteps": null, "Note": "通知保存成功", "Disabled": false, "Collapsed": false, "DelayMs": 0, "Id": "b1a00001-0006-4000-8000-000000000006"}]}
